import os
import logging
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1

# Create a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher)
PROJECT_ID = 'your-project-id'
SERVICE_ACCOUNT_KEY_FILE = 'path/to/service/account/key.json'

def process_file(bucket_name, file_name):
    # Authenticate using the service account key
    os.environ['GOOGLE_APPLICATION_CREDENTIALS'] = SERVICE_ACCOUNT_KEY_FILE

    # Get a client for Cloud Storage
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    # Download the file from Cloud Storage
    blob.download_to_filename(f'/tmp/{file_name}')

    # Process the file (e.g., read its contents, perform some operation)
    with open(f'/tmp/{file_name}', 'r') as f:
        data = f.read()

    # Write the processed data to Firestore
    db = firestore.Client()
    doc_ref = db.collection('your-collection').document(file_name)
    doc_ref.set({'data': data})

    # Publish a message to Pub/Sub
    pubsub_client = pubsub_v1.PublisherClient()
    topic_path = f'projects/{PROJECT_ID}/topics/your-topic'
    pubsub_client.publish(topic_path, data=data.encode('utf-8'))

def main(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    process_file(bucket_name, file_name)

# Set up logging
logging.basicConfig(level=logging.INFO)